mapper.select:
SELECT lot_num, lot_code, item_name, code, current_qty, lot_date, type, total_count FROM ( SELECT inner_q.*, ROWNUM AS rn FROM ( SELECT l.lot_num, l.lot_code, i.name AS item_name, i.code, l.current_qty, l.lot_date,
i.type, COUNT(*) OVER() AS total_count FROM lot l LEFT JOIN item i ON l.item_num = i.item_num
AND l.lot_date >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND l.lot_date <= TO_DATE(#{endDate}, 'YYYY-MM-DD')
AND i.type = #{item_type}
AND l.item_num = #{item_num}
AND (l.lot_code LIKE '%' || #{keyword} || '%' OR i.name LIKE '%' || #{keyword} || '%')
ORDER BY l.lot_num DESC ) inner_q WHERE ROWNUM <= #{endRow} ) WHERE rn >= #{startRow}

mapper.update:
UPDATE lot
SET current_qty = current_qty - #{deduct_qty}
WHERE lot_num = #{lot_num}
  AND current_qty >= #{deduct_qty}
  AND #{deduct_qty} > 0

mapper.select:
SELECT ROWNUM AS seq_num, depth, lot_code, item_name, item_type, gubun, id_col, content_col, date_col, status_col, worker FROM ( SELECT level_num AS depth, lot_code, item_name, item_type, gubun, id_col, content_col, date_col, status_col, worker, reg_date, flow_order, ord_seq FROM ( /* ── [0] 입출고 이력 (입고: 자재롯+현재롯 / 생산투입출고: 현재롯) ── */ SELECT 0 AS level_num, 2 AS sort_phase, l.lot_code AS lot_code, i.name AS item_name, i.type AS item_type, CASE WHEN io.io_type = '입고' THEN '입고' WHEN io.io_reason = '생산투입' THEN '생산투입' ELSE '출고' END AS gubun, TO_CHAR(io.io_num) AS id_col, f.facility_name || ' / ' || io.io_qty AS content_col, TO_CHAR(io.io_date, 'YYYY-MM-DD') AS date_col, io.io_reason AS status_col, e.ename AS worker, io.io_date AS reg_date, 0 AS flow_order, io.io_num AS ord_seq FROM io io JOIN lot l ON io.lot_num = l.lot_num JOIN item i ON l.item_num = i.item_num LEFT JOIN facility f ON io.facility_num = f.facility_num LEFT JOIN emp e ON io.emp_num = e.emp_num WHERE io.lot_num = #{prodLot} -- 자기 LOT 입출고만 (입고·출고 모두)
UNION ALL
/* ── [2] 현재 완제품 LOT의 진행 공정 종합 (공정 flow 순서대로 각 공정 단계 표시) ── */ SELECT 2 AS level_num, 1 AS sort_phase, l.lot_code AS lot_code, i.name AS item_name, i.type AS item_type, '제품생산' AS gubun, wo.order_id AS id_col, /* 위치(시설) / 수량(LOT 초기수량) */ (SELECT f.facility_name FROM ( SELECT item_num, facility_num, ROW_NUMBER() OVER (PARTITION BY item_num ORDER BY flow) AS rn FROM process WHERE facility_num IS NOT NULL ) pr JOIN facility f ON pr.facility_num = f.facility_num WHERE pr.item_num = pp.item_num AND pr.rn = 1) || ' / ' || l.init_qty AS content_col, TO_CHAR(wo.order_start, 'YYYY-MM-DD HH24:MI:SS') AS date_col, wo.order_status AS status_col, e.ename AS worker, NVL(wo.order_start, l.lot_date) AS reg_date, 1 AS flow_order, 0 AS ord_seq FROM lot l JOIN item i ON l.item_num = i.item_num JOIN work_order wo ON l.order_num = wo.order_num LEFT JOIN production_plan pp ON wo.plan_num = pp.plan_num LEFT JOIN emp e ON wo.emp_num = e.emp_num WHERE l.lot_num = #{prodLot}
UNION ALL
/* ── [3] 최종 출하 단계 종합 ── */ SELECT 3 AS level_num, 3 AS sort_phase, l.lot_code AS lot_code, i.name AS item_name, i.type AS item_type, '출하완료' AS gubun, s.shipment_id AS id_col, /* 위치(거래처) / 수량(출하수량) */ v.vender_name || ' / ' || sl.qty AS content_col, TO_CHAR(s.shipment_date, 'YYYY-MM-DD HH24:MI:SS') AS date_col, s.shipment_status AS status_col, e.ename AS worker, s.shipment_date AS reg_date, 999 AS flow_order, 0 AS ord_seq FROM lot l JOIN item i ON l.item_num = i.item_num JOIN shipment_lot sl ON sl.lot_num = l.lot_num JOIN shipment s ON sl.shipment_num = s.shipment_num JOIN shipment_request sr ON s.shipment_request_num = sr.shipment_request_num JOIN vender v ON sr.vender_num = v.vender_num LEFT JOIN emp e ON s.emp_num = e.emp_num WHERE l.lot_num IN ( SELECT split_lot_num FROM lot_split START WITH origin_lot_num = #{selfLot} CONNECT BY PRIOR split_lot_num = origin_lot_num UNION SELECT #{selfLot} FROM DUAL ) ) /* 단계: 자재 → 제품생산 → 이 LOT 입출고 → 출하, 동일 단계는 시각·생성순 */ ORDER BY sort_phase ASC, reg_date ASC, flow_order ASC, ord_seq ASC )
